import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useHistory } from 'react-router';
import PropTypes from 'prop-types';
import * as actions from '../../redux/actions';

import { useForm, Controller } from 'react-hook-form';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Modal from '@mui/material/Modal';

import { Button } from '@mui/material';

import FilterExpensesDaily from 'components/Card/FilterExpensesDaily';
import DatePickerCard from 'components/Card/DatePickerCard';
import PaymentListTable from '../../components/Table/PaymentListTable';
import Loading from 'components/Loading';

const style = {
  position: 'absolute',
  top: '50%',
  left: '50%',
  transform: 'translate(-50%, -50%)',
  width: 600,
  maxWidth: '90vw',
  maxHeight: '90vh',
  bgcolor: 'background.paper',
  borderRadius: 3,
  boxShadow: '0 8px 32px rgba(0, 0, 0, 0.12)',
  overflow: 'hidden',
  display: 'flex',
  flexDirection: 'column',
};

const Payment = ({ title, subtitle }) => {
  const dispatch = useDispatch();
  const history = useHistory();
  const {
    control,
    formState: { errors },
    handleSubmit,
    reset,
    setValue,
  } = useForm();

  const payments = useSelector((state) => state.payments);

  const [page, setPage] = useState(1);
  const [size, setSize] = useState(20);
  const [open, setOpen] = React.useState(false);
  const [date, setDate] = useState(null);

  const handleOpen = () => setOpen(true);
  const handleClose = () => setOpen(false);

  const handleOnclickDetail = (id) => {
    // history.push(`/finance/payment/${id}`);
  };

  const onClickDelete = async (id) => {
    const confirm = window.confirm('คุณต้องการลบรายการนี้ใช่หรือไม่?');
    if (confirm) {
      try {
        await dispatch(actions.paymentDelete(id));
        await dispatch(actions.paymentAll({ page, size }));
      } catch (error) {
        console.error(error);
      }
    }
  };

  useEffect(() => {
    dispatch(actions.paymentAll({ page, size }));
    return () => {};
  }, [page, size]);

  const handleCreatePayment = async () => {
    await dispatch(actions.paymentCreateWithExpenses({ date }));
    await dispatch(actions.paymentAll({ page, size }));
    handleClose();
  };


  const renderAddButton = () => (
    <div>
      <Button
        variant="contained"
        color="primary"
        // onClick={() => history.push('/finance/payment/add')}
        onClick={handleOpen}
      >
        สร้างรายการจ่ายเงิน
      </Button>
    </div>
  );

  const renderModal = () => (
    <Modal
      open={open}
      onClose={handleClose}
      aria-labelledby="modal-modal-title"
      aria-describedby="modal-modal-description"
    >
      <Box sx={style}>
        {/* Header */}
        <Box
          sx={{
            px: 3,
            py: 2.5,
            borderBottom: '1px solid',
            borderColor: 'divider',
            bgcolor: 'primary.main',
            color: 'white',
          }}
        >
          <Typography
            id="modal-modal-title"
            variant="h5"
            component="h2"
            sx={{ fontWeight: 600 }}
          >
            สร้างรายการจ่ายเงิน
          </Typography>
        </Box>

        {/* Content */}
        <Box
          id="modal-modal-description"
          sx={{
            p: 3,
            overflowY: 'auto',
            flex: 1,
          }}
        >
          <DatePickerCard setDate={setDate} date={date} />
        </Box>

        {/* Footer */}
        <Box
          sx={{
            px: 3,
            py: 2,
            borderTop: '1px solid',
            borderColor: 'divider',
            display: 'flex',
            justifyContent: 'flex-end',
            gap: 2,
            bgcolor: 'grey.50',
          }}
        >
          <Button
            variant="outlined"
            onClick={handleClose}
            sx={{ minWidth: 100 }}
          >
            ยกเลิก
          </Button>
          <Button
            variant="contained"
            color="primary"
            sx={{ minWidth: 100 }}
            onClick={handleCreatePayment}
          >
            สร้างรายการ
          </Button>
        </Box>
      </Box>
    </Modal>
  );
  const renderTable = () => (
    <PaymentListTable
      payments={payments}
      page={page}
      setPage={setPage}
      size={size}
      setSize={setSize}
      handleOnclickDetail={handleOnclickDetail}
      onClickDelete={onClickDelete}
    />
  );
  // if (payments?.isLoading || !payments?.isCompleted) {
  //   return <Loading isLoading />;
  // }
  return (
    <div>
      {renderModal()}
      <div className="py-1 flex justify-end">{renderAddButton()}</div>
      <div>{renderTable()}</div>
    </div>
  );
};

export default Payment;
